use std::sync::{Arc, Mutex, RwLock};
use std::thread;
use std::collections::HashMap;

#[derive(Debug, Clone)]
pub struct InventoryItem {
    pub id: String,
    pub stock: i32,
    pub reserved: i32,
}

#[derive(Debug)]
pub struct InventoryManager {
    items: Arc<RwLock<HashMap<String, InventoryItem>>>,
}

impl InventoryManager {
    pub fn new() -> Self {
        Self {
            items: Arc::new(RwLock::new(HashMap::new())),
        }
    }

    pub fn add_item(&self, id: String, stock: i32) {
        let mut items = self.items.write().unwrap();
        items.insert(id, InventoryItem {
            id: id.clone(),
            stock,
            reserved: 0,
        });
    }

    pub fn check_stock(&self, id: &str) -> Option<i32> {
        let items = self.items.read().unwrap();
        items.get(id).map(|item| item.stock)
    }

    pub fn reserve_stock(&self, id: &str, quantity: i32) -> Result<bool, String> {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(id) {
            if item.stock - item.reserved >= quantity {
                item.reserved += quantity;
                Ok(true)
            } else {
                Ok(false)
            }
        } else {
            Err("Item not found".to_string())
        }
    }

    pub fn commit_reservation(&self, id: &str, quantity: i32) -> Result<bool, String> {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(id) {
            if item.reserved >= quantity {
                item.stock -= quantity;
                item.reserved -= quantity;
                Ok(true)
            } else {
                Err("Not enough reserved stock".to_string())
            }
        } else {
            Err("Item not found".to_string())
        }
    }

    pub fn cancel_reservation(&self, id: &str, quantity: i32) -> Result<bool, String> {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(id) {
            if item.reserved >= quantity {
                item.reserved -= quantity;
                Ok(true)
            } else {
                Err("Not enough reserved stock to cancel".to_string())
            }
        } else {
            Err("Item not found".to_string())
        }
    }

    pub fn update_stock(&self, id: &str, new_stock: i32) -> Result<bool, String> {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(id) {
            item.stock = new_stock;
            Ok(true)
        } else {
            Err("Item not found".to_string())
        }
    }
}

pub fn concurrent_inventory_update(
    inventory: Arc<InventoryManager>,
    item_id: String,
    operations: Vec<(i32, bool)>, // (quantity, should_commit)
) -> Result<(), String> {
    let mut handles = vec![];
    
    for (quantity, should_commit) in operations {
        let inventory_clone = Arc::clone(&inventory);
        let item_id_clone = item_id.clone();
        
        let handle = thread::spawn(move || {
            let result = inventory_clone.reserve_stock(&item_id_clone, quantity);
            if let Ok(true) = result {
                if should_commit {
                    inventory_clone.commit_reservation(&item_id_clone, quantity)
                } else {
                    inventory_clone.cancel_reservation(&item_id_clone, quantity)
                }
            } else {
                Ok(false)
            }
        });
        
        handles.push(handle);
    }
    
    for handle in handles {
        handle.join().unwrap()?;
    }
    
    Ok(())
}

